package org.jsoup.nodes;

import org.junit.runner.RunWith;
import io.cucumber.junit.Cucumber;
import io.cucumber.junit.CucumberOptions;

@RunWith(Cucumber.class)
@CucumberOptions(
    features = "src/test/resources/requirement.feature",
    glue = "org.jsoup.nodes.steps"
)
public class CucumberTest {
    // This is a JUnit runner for Cucumber tests
}

package org.jsoup.nodes.steps;

import io.cucumber.java.en.Given;
import io.cucumber.java.en.When;
import io.cucumber.java.en.Then;
import org.jsoup.Jsoup;
import org.jsoup.nodes.Document;
import org.jsoup.nodes.Element;
import org.jsoup.parser.Parser;
import static org.junit.Assert.*;

public class StepDefs {
    private Document doc;
    private Parser parser;
    private boolean isCaseSensitive = false;

    @Given("the parser is configured to preserve case")
    public void the_parser_is_configured_to_preserve_case() {
        isCaseSensitive = true;
    }

    @Given("the parser is configured to default settings")
    public void the_parser_is_configured_to_default_settings() {
        isCaseSensitive = false;
    }

    @When("I parse the HTML {string}")
    public void i_parse_the_HTML(String html) {
        try {
            if (isCaseSensitive) {
                // Jsoup doesn't have a direct case-sensitive attribute parsing option
                // We'll parse with the default parser but check the expected behavior
                doc = Jsoup.parse(html);
            } else {
                doc = Jsoup.parse(html);
            }
        } catch (Exception e) {
            fail("Exception occurred while parsing HTML: " + e.getMessage());
        }
    }

    @Then("the element should have attribute {string} with value {string}")
    public void the_element_should_have_attribute_with_value(String attrName, String attrValue) {
        Element element = doc.select("p").first();
        assertNotNull("Element should exist", element);
        assertTrue("Element should have attribute " + attrName, element.hasAttr(attrName));
        assertEquals("Attribute " + attrName + " should have value " + attrValue,
                     attrValue, element.attr(attrName));
    }

    @Then("the generated HTML should be {string}")
    public void the_generated_HTML_should_be(String expectedHtml) {
        String actualHtml = doc.body().child(0).outerHtml();
        assertEquals("Generated HTML should match expected", expectedHtml, actualHtml);
    }
}

